import{_ as t,o as n,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt1602.jpg",p="/images/lekt1601.jpg",s="/images/lekt1603.jpg",o="/images/lekt1604.jpg",g=JSON.parse('{"title":"Lektion 16","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion16.md","filePath":"lektionen/lektion16.md"}'),l={name:"lektionen/lektion16.md"};function d(h,e,u,c,m,b){return n(),a("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-16" tabindex="-1">Lektion 16 <a class="header-anchor" href="#lektion-16" aria-label="Permalink to &quot;Lektion 16&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>16.1. Zum Sandhi auslautender Konsonanten</li><li>16.2. Wortliste</li><li>16.3. Übung</li><li>16.4. Wiederholungsübung</li></ul><h2 id="_16-1-zum-sandhi-auslautender-konsonanten" tabindex="-1">16.1. Zum Sandhi auslautender Konsonanten <a class="header-anchor" href="#_16-1-zum-sandhi-auslautender-konsonanten" aria-label="Permalink to &quot;16.1. Zum Sandhi auslautender Konsonanten&quot;">​</a></h2><p>Zur Bildung von Komposita, deren Vorderglied konsonantisch auslautende Stämme bilden, benötigt man folgende Regeln:</p><p>Auslautende gutturale, retroflexe, dentale und labiale Verschlusslaute (d.h. keine Nasale und keine Palatale).</p><p>| in Pausa und vor stimmlosen Lauten | Ersetzung durch den ihnen entsprechenden stimmlosen nicht-aspirierten Laut: z.B.</p><blockquote><p>-g + p- » -kp-<br> -d + ph- » -tph-<br> -dh + p- » -tp-</p></blockquote><p>| | --- | --- | | vor stimmhaften nichtnasalen Lauten | Ersetzung durch den ihnen entsprechenden stimmhaften nicht-aspirierten Laut:</p><p>z.B.</p><blockquote><p>-t + g- » -dg-<br> -k + b- » -gb-<br> -dh + d- » -dd-<br> -k + a- » -ga-</p></blockquote><p>| | vor Nasalen | Ersetzung durch den ihnen entsprechenden Nasal:</p><p>z.B.</p><blockquote><p>-t + n- » -nn-<br> -p + n- » -mn-</p></blockquote><p>|</p><p>Ausnahme zu obiger Regel:</p><p>Auslautender dentaler Verschlusslaut (nicht Nasal):</p><p>| vor Palatal | Ersetzung durch betreffenden unaspirierten Palatal: d.h.</p><blockquote><p>-t + c- » -cc-<br> -d + c- » -cc-<br> -th + c- » -cc-<br> -dh + c- » -cc-<br> -t/-th/-d/-dh + ch- » -cch-<br> -t/-th/-d/-dh + j- » -jj-<br> -t/-th/-d/-dh + jh- » -jjh-</p></blockquote><p>| | --- | --- | | + ś |  » -cś- oder -cch- | | vor Retroflex | Ersetzung durch betreffenden unaspirierten Retroflex:</p><p>d.h.</p><blockquote><p>-t/-th/-d/-dh + ṭ(h)- » -ṭṭ(h)-<br> -t/-th/-d/-dh + ḍ(h)- » -ḍḍ(h)-</p></blockquote><p>| | vor l- | Ersetzung durch -l:</p><p>d.h.</p><blockquote><p>-t/-th/-d/-dh + l- » -ll-</p></blockquote><p>|</p><p>Beispiele:</p><p>तद् + फल = तत्फल</p><p>पुण्यवत् + ब्राह्मण = पुण्यवद्ब्राह्मण</p><p>पुण्यवत् + नर = पुण्यवन्नर</p><p>पुण्यवत् + पुरुष = पुण्यवत्पुरुष</p><p>सत्यवत् + चैतन्य =सत्यवच्चैतन्य</p><p>सुखवत् + लोक = सुखवल्लोक</p><p>पुत्रवत् + जन = पुत्रवज्जन</p><p>बलवत् + शत्रु = बलवच्छत्रु</p><h2 id="_16-2-wortliste" tabindex="-1">16.2. Wortliste <a class="header-anchor" href="#_16-2-wortliste" aria-label="Permalink to &quot;16.2. Wortliste&quot;">​</a></h2><p>अध्यापन n.: Unterrichten, Unterricht</p><p><img src="'+i+'" alt=""><br> Abb.: अध्यापनम्</p><blockquote><p>&quot;This is a special ceremony in a small temple in Satara (सातारा). It is performed by the students of the Swami Muktananda Vedashala on the celebration of Mahāśivarātri. This is a vedic school, where children by heart the sacred texts called the Vedas. This school teaches the Krishna Yajurveda and some portions of the Samaveda. I&#39;m doing my master&#39;s thesis on this school.&quot;</p><p>[Bildquelle: Shrimaitreya. -- <a href="http://www.flickr.com/photos/shrimaitreya/339418301/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/shrimaitreya/339418301/</a>. -- Zugriff am 2008-12-07. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p></blockquote><p>अनसूया f.: Nicht-Murren, Neidlosigkeit</p><p>नृशंस्य n.: Boshaftigkeit, Niedertracht</p><p>davon:</p><blockquote><p>अनृशंस्य n.: Nicht-Boshaftigkeit</p></blockquote><p>जीव् 1 P जीवति ; Pass. जीव्यते ; PPP जीवित : leben</p><p>davon:</p><blockquote><p>आजीव m.: Lebensunterhalt</p></blockquote><p>क्षमा f.: Geduld, Langmut, Nachsicht</p><p>क्षेम n.: Ruhe, Frieden, Wohlergehen, sicherer Besitz</p><p>चित्त n.: Bewusstsein, Denken, Geist</p><p>निरोध m.: Stoppen, Zum-Stillstand-Bringen</p><p>भुत n. (PPP zu भु): Wesen, Gespenst</p><p>योग m.: Anschirrung, Verbindung, Vereinigung, Erwerb ; Yoga</p><p><img src="'+p+'" alt=""><br> Abb.: योगी<br> Birla Mandir, Delhi<br> [Bildquelle: Deepak / Wikipedia ; <a href="http://creativecommons.org/licenses/by-sa/2.0/de/deed.en" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>वृत्  1 Ā वर्तते ; Pass. वृत्यते  ; PPP वृत्त : sich drehen, sich wenden, sich (irgendwo) befinden, wohnen</p><p>शस्त्र (śastra) n.: Schneidewerkzeug, Schneidewaffe, Schwert, Waffe</p><p>शौच n.: Reinigung, Reinheit</p><p>साधन m.,n. साधनी साधना f.: zum Ziel führend, bewirkend</p><p>अहिंसा f.: das Niemandem-etwas-zu-Leide-Tun, Nichtverletzen, Gewaltlosigkeit</p><p><img src="'+s+'" alt=""><br> Abb.: अहिंसा<br> &quot;The hand with a wheel on the palm symbolizes the Jain Vow of Ahimsa. The word in the middle is &quot;ahimsa&quot;. The wheel represents the dharmacakra which stands for the resolve to halt the cycle of reincarnation through relentless pursuit of truth and non-violence.&quot;<br> [Bildquelle: Wikipedia, Public domain]</p><h2 id="_16-3-ubung" tabindex="-1">16.3. Übung <a class="header-anchor" href="#_16-3-ubung" aria-label="Permalink to &quot;16.3. Übung&quot;">​</a></h2><p>A) Wandeln sie folgende Ausdrücke in Tatpuruṣa um und übersetzen Sie sie:</p><p>१. देवस्य पुरुषः ।</p><p>२. गुणवती ब्राह्मणी ।</p><p>३. सत्यवान्ब्राह्मणः ।</p><p>४. पशुमन्तो जनाः ।</p><p><img src="'+o+'" alt=""><br> Abb.: पशुमन्तो जनाः<br> हरियाणा / ਹਰਿਆਣਾ<br> [Bildquelle: mksfoto. -- <a href="http://www.flickr.com/photos/mksfoto/583024679/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mksfoto/583024679/</a>. -- Zugriff am 2008-12-07. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzelle Nutzung, keine Bearbeitung)]</p><p>५. सुखवान्वैश्यायाः पुत्रः ।</p><p>६.  सुखवत्या वैश्यायाः पुत्रः ।</p><p>७. कवेरुक्त्याः सत्यम् ।</p><p>८. शिवेन रक्षिता बाला ।</p><p>९. रामेण पीतं जलम् ।</p><p>१०. फलवांल्लाभः ।</p><p>११. इष्टाया देवतायाः पूजा ।</p><p>१२. देवानां स्तुतिः ।</p><p>B) Lösen Sie in folgenden Sätzen alle Komposita in Sanskrit auf, bilden Sie so Sätze mit flektierten Nomina und übersetzen Sie:</p><p>१. पुण्यवद्वैश्यपुत्रो देवेन्द्रलोकं गच्छति ।</p><p>२. पुण्यकरणं स्वर्गमार्गः ।</p><p>३. न साधुः पशुवन्नरधेनुलोभः ।</p><p>४. न पशुयज्ञैर्नराः स्वर्गं गच्छन्ति । धर्मयज्ञैस्तु स्वर्गसुखमाप्नुवन्ति ।</p><p>५. द्विजदासा इति शूद्रा उच्यन्ते ।</p><p>६. बालब्राह्मणपुत्राः सत्यवन्नरं शृण्वन्ति ।</p><p>७. बलवत्क्षत्रिया धनवच्छत्रुनगरं जयन्ति ।</p><p>८. ऋष्युक्त्या सत्यमुच्यते ।</p><p>९. बलवद्योधा ब्राह्मणग्रामं गताः ।</p><p>१०. पुण्यवद्वैश्येष्टवेवतापूजां करोति ।</p><h2 id="_16-4-wiederholungsubung" tabindex="-1">16.4. Wiederholungsübung <a class="header-anchor" href="#_16-4-wiederholungsubung" aria-label="Permalink to &quot;16.4. Wiederholungsübung&quot;">​</a></h2><p>A) Bilden Sie alle bisher gelernten Kasus zu folgenden Wörtern als Beispiele für die bisher gelernten Deklinationsklassen.</p><p>Verwenden Sie dazu folgendes Schema, das der Reihenfolge der Kasus bei den indischen Grammatikern entspricht und das wegen seiner - später zu besprechenden - Vorzüge auch von den westlichen Grammatikern übernommen wurde:</p><table tabindex="0"><thead><tr><th>एकवचनम् Singular</th><th>बहुवचनम् Plural</th></tr></thead><tbody><tr><td>१. प्रथमा Nominativ</td><td>१. प्रथमा</td></tr><tr><td>२. द्वितीया Akkusativ</td><td>२. द्वितीया</td></tr><tr><td>३. तृतीया Instrumentalis</td><td>३. तृतीया</td></tr><tr><td>६. षष्ठी Genetiv</td><td>६. षष्ठी</td></tr></tbody></table><p>Lernen Sie die Deklinationsmuster nach diesen Beispielen auswendig!!!</p><p>१. नर m.</p><p>२. फल n.</p><p>३. क्षत्रिया f.</p><p>४. अरि m.</p><p>५. मति f.</p><p>६. गुरु m.</p><p>७. धेनु f.</p><p>८. देवी f.</p><p>९. गुणवन्त् m., n., f.</p><p>१०. किम्  m., n., f.</p><p>११. तद् m., n., f.</p><p>१२. एतद् m., n., f.</p><p>१३. इदम् m., n., f.</p><p>B) Übersetzen Sie und lösen Sie alle Komposita in Sanskrit auf:</p><p>१. योगश्चित्तवृत्तिनिरोधः ॥योगसूत्र १.२॥</p><p>२. स्वधर्मो ब्राह्मणस्याध्ययनमध्यापनं यजनं याजनं दानं प्रतिग्रहश्च ॥५॥</p><p>क्षत्रियस्याध्ययनं यजनं दानं शस्त्राजीवो भूतरक्षणं च ॥६॥</p><p>वैश्यस्याध्ययनं यजनं दानं कृषिपाशुपाल्ये वणिज्या च ॥७॥</p><p>शूद्रस्य द्विजातिशुश्रूषा वार्त्ता कारुकुशीलवकर्म च ॥८॥</p><p>सर्वेषामहिंसा सत्यं शौचमनसूयानृशंस्यं क्षमा च ॥१३॥</p><p>(कौटिलीयार्थशास्त्र १.३.५-८, १३)</p><blockquote><p>Erklärungen;</p><p>Satz 7: कृषिपाशुपाल्ये Dual, Nom. Akk.: Dvandva, das zwei &quot;Sachen&quot; bezeichnet</p><p>Satz 8: कर्म Nom., Akk. sg. Neutrum zu कर्मन् &quot;Tat&quot;</p><p>Satz 13: सर्वेषाम् Gen. pl. mask. zu सर्व &quot;jeder, alle&quot; (Pronomen, dekliniert nicht wie deva)</p></blockquote><p>३. आन्वीक्षिकीत्रयीवार्त्तानां योगक्षेमसाधनो दण्डः, तस्य नीतिर्दण्डनीतिः ॥कौटिलीयार्थशास्त्र १.४.३॥</p>',114)])])}const f=t(l,[["render",d]]);export{g as __pageData,f as default};
